#!/bin/bash
set -e
cd "$(dirname "$0")"
python3 -c "import base64; open('scripts/generate-article.mjs', 'wb').write(base64.b64decode(''))"
echo "✅ generate-article.mjs 修正"
git add scripts/generate-article.mjs
git commit -m "fix: TypeScript check - use local tsc binary, skip if not found"
git push origin main
echo ""
echo "🚀 Push完了！"
echo ""
echo "=== cron設定（これだけ残り！） ==="
echo "crontab -e で以下3行を追加:"
echo ""
echo "0 7 * * * cd ~/Downloads/kyuryo-lab && bash scripts/daily-agent.sh >> scripts/logs/cron.log 2>&1"
echo "0 8 * * 1,4 cd ~/Downloads/kyuryo-lab && bash scripts/run-pipeline.sh >> scripts/pipeline.log 2>&1"
echo "0 9 * * 0 cd ~/Downloads/kyuryo-lab && node scripts/analyze-and-improve.mjs >> scripts/analysis.log 2>&1"
echo ""
echo "✅ 設定完了後、明日の朝7時から毎日自動実行されます"
